import { verifier } from "..";
import { z } from "zod";

interface TransferIntent {
    intent: "transfer";
    data: {
        to: string;
        value: bigint;
    };
}

interface SwapIntent {
    intent: "swap";
    data: {
        amountIn: bigint;
        amountOutMin: bigint;
        path: [from: string, to: string];
        to: string;
        deadline: bigint | null;
    };
}

const trasfer_calldata = "0xa9059cbb000000000000000000000000a0b86991c6218b36c1d19d4a2e9eb0ce3606eb48000000000000000000000000000000000000000000000000000000000001e1b0";
const pancakeswap_calldata = "";
const kyberswap_calldata = "";


const calldataIntentData = verifier.getIntent<TransferIntent>(trasfer_calldata);
const toAddress = "0xA0b86991c6218b36c1d19D4a2e9Eb0cE3606eB48";
const amount = 1000000000000000000n;


// ---- transfer validation ----
const { valid, errors } = await verifier.check(calldataIntentData, z.object({
    to: z.literal(toAddress),
    // value: z.literal(amount),
    value: z.bigint().gt(100000n)
}));

if (valid) {
    console.log("Transfer is valid");
} else {
    console.log("Transfer is invalid");
    console.log(errors);
}
// --------------------------

// ---- swap validation ----
const swapIntent = verifier.getIntent<SwapIntent>(pancakeswap_calldata);
console.log(swapIntent);
const expectedAmountIn = 1000000000000000000n;
const expectedTokenIn = "0xbb4CdB9CBd36B01bD1cBaEBF2De08d9173bc095c";
const expectedTokenOut = "0xCC42724C6683B7E57334c4E856f4c9965ED682bD";

const { valid: validSwap, errors: errorsSwap } = await verifier.check(swapIntent, z.object({
    amountIn: z.literal(120000000n),
    amountOutMin: z.bigint(),
    path: z.array(z.string()).min(2).check((payload) => {
        const [tokenIn, tokenOut] = payload.value;
        if (tokenIn !== expectedTokenIn || tokenOut !== expectedTokenOut) {
            throw new Error("Invalid path");
        }
    }),
    to: z.string(),
    deadline: z.null().or(z.bigint().check((payload) => {
        // If deadline is more than 1 hour from now, throw an error

        const now = Date.now();
        const deadline = payload.value;
        const oneHourFromNow = now + 1000 * 60 * 60;

        if (deadline > oneHourFromNow) {
            throw new Error("Deadline must be less than 1 hour from now");
        }
    })),
}));

if (validSwap) {
    console.log("Swap is valid");
} else {
    console.log("Swap is invalid");
    console.log(errorsSwap);
}
// --------------------------